Real-World Example

LED Blink with Timer

Putting it all together, the example from your code:
// timer.c
volatile unsigned int timer1Count = 0;

void __attribute__((interrupt, auto_psv)) _T1Interrupt(void) {
    timer1Count++;
    IFS0bits.T1IF = 0;
}

void timer1Init(uint16_t period) {
    T1CON = 0x0030;      // Prescaler 1:256
    TMR1 = 0;
    PR1 = period;
    IPC0bits.T1IP = 4;
    IFS0bits.T1IF = 0;
    IEC0bits.T1IE = 1;
    T1CONbits.TON = 1;
}
// main.c
#include "timer.h"

extern volatile unsigned int timer1Count;

int main(void) {
    init_hardware();

    // Timer interrupts every 100ms
    timer1Init(15625);  // (40MHz / 4) / 256 / 15625 = 10Hz

    while(1) {
        RED_LED = 1;
        while(timer1Count &lt; 10);  // Wait 1 second (10 × 100ms)
        timer1Count = 0;

        RED_LED = 0;
        while(timer1Count &lt; 10);
        timer1Count = 0;
    }
}

How it works

Timer 1 fires every 100ms, incrementing timer1Count in the ISR
Main loop waits for counter to reach 10 (1 second), then resets it
LED blinks on/off with 1 second periods

This is exactly the pattern you encountered; now you know what’s happening behind the scenes!

Embedded C Idioms

State Machines
Many embedded systems are best modeled as finite state machines:
typedef enum {
    STATE_IDLE,
    STATE_ACQUIRING,
    STATE_PROCESSING,
    STATE_ERROR
} State_t;

static State_t current_state = STATE_IDLE;

void state_machine_update(void) {
    switch(current_state) {
        case STATE_IDLE:
            if(start_button_pressed()) {
                current_state = STATE_ACQUIRING;
                init_acquisition();
            }
            break;

        case STATE_ACQUIRING:
            if(buffer_full()) {
                current_state = STATE_PROCESSING;
            } else if(timeout_occurred()) {
                current_state = STATE_ERROR;
            }
            break;

        case STATE_PROCESSING:
            process_buffer();
            current_state = STATE_IDLE;
            break;

        case STATE_ERROR:
            handle_error();
            current_state = STATE_IDLE;
            break;
    }
}

Benefits

Clear, maintainable code
Easy to visualize as a diagram
Deterministic behavior




Ring Buffers

Circular Buffers

Essential for continuous data streams (audio, serial data):
#define BUFFER_SIZE 256  // Must be power of 2 for fast modulo

typedef struct {
    int16_t buffer[BUFFER_SIZE];
    volatile uint16_t head;  // Write position (ISR writes)
    volatile uint16_t tail;  // Read position (main reads)
} RingBuffer_t;

// ISR writes
void buffer_write(RingBuffer_t *rb, int16_t value) {
    rb-&gt;buffer[rb-&gt;head] = value;
    rb-&gt;head = (rb-&gt;head + 1) & (BUFFER_SIZE - 1);  // Fast modulo
}

// Main loop reads
int16_t buffer_read(RingBuffer_t *rb) {
    int16_t value = rb-&gt;buffer[rb-&gt;tail];
    rb-&gt;tail = (rb-&gt;tail + 1) & (BUFFER_SIZE - 1);
    return value;
}

// Check if data available
int buffer_available(RingBuffer_t *rb) {
    return (rb-&gt;head - rb-&gt;tail) & (BUFFER_SIZE - 1);
}
Why power of 2? Modulo becomes a simple AND: x % 256 ≡ x & 255 (much faster).
Why volatile? The ISR and main loop access these independently; the compiler must not optimize away reads.


Bit Fields for Hardware Registers
typedef struct {
    unsigned pin0  : 1;
    unsigned pin1  : 1;
    unsigned pin2  : 1;
    unsigned       : 5;  // Reserved bits
    unsigned mode  : 2;
    unsigned       : 6;  // Reserved
} ControlRegister_t;

volatile ControlRegister_t *ctrl_reg = (ControlRegister_t*)0x0040;

// Access individual bits
ctrl_reg-&gt;pin0 = 1;
ctrl_reg-&gt;mode = 2;
Caveat: Bit field layout is compiler-dependent. For portable code, use bitwise operations instead.

TRISCBITS is a bit field and is used to control the direction of pins on Port C: whether each pin is an input or output. This struct overlays the 16-bit TRISC hardware register, giving you named access to individual bits instead of having to manually mask and shift.
It’s in p33FJ256GP506.h which is included via xc.h (which is the chip selector). We use it in BlinkBlocking.
#define TRISC TRISC
extern volatile uint16_t TRISC __attribute__((__sfr__));
typedef struct tagTRISCBITS {
  uint16_t :1;
  uint16_t TRISC1:1;
  uint16_t TRISC2:1;
  uint16_t :9;
  uint16_t TRISC12:1;
  uint16_t TRISC13:1;
  uint16_t TRISC14:1;
  uint16_t TRISC15:1;
} TRISCBITS;
extern volatile TRISCBITS TRISCbits __attribute__((__sfr__));
Breaking down TRISCBITS:

uint16_t :1; - Anonymous 1-bit field (bit 0) - reserved/unused pin
uint16_t TRISC1:1; - Named 1-bit field for pin C1 (bit 1)
uint16_t TRISC2:1; - Pin C2 (bit 2)
uint16_t :9; - Anonymous 9-bit field (bits 3-11) - pins that don’t exist on Port C
uint16_t TRISC12:1; - Pins C12 (bit 12)
uint16_t TRISC13:1; - Pins C13 (bit 13)
uint16_t TRISC14:1; - Pins C14 (bit 14)
uint16_t TRISC15:1; - Pins C15 (bit 15)

The TRISC register controls pin direction on Port C:

TRISCbits.TRISC1 = 0; → Pin C1 is an output
TRISCbits.TRISC1 = 1; → Pin C1 is an input

Functions and Closures

First-Class Functions
Functions are objects. They can be passed, returned, and stored:
def apply(func, value):
    return func(value)

def double(x):
    return x * 2

apply(double, 5)            # 10
apply(lambda x: x * 3, 5)  # 15: anonymous function


Closures
A nested function can capture variables from its enclosing scope:
def make_multiplier(n):
    def multiply(x):
        return x * n   # captures n from the enclosing scope
    return multiply

triple = make_multiplier(3)
triple(7)   # 21
This is the same concept as Rust closures or C++ lambdas with captures. Unlike Rust, Python does not distinguish capture by reference from capture by value: closures always capture a reference to the enclosing scope’s variable binding.


Decorators
A decorator is a function that wraps another function. The @ syntax is shorthand for applying the wrapper:
def log_calls(func):
    def wrapper(*args, **kwargs):
        print(f"calling {func.__name__}")
        return func(*args, **kwargs)
    return wrapper

@log_calls
def add(a, b):
    return a + b

# equivalent to: add = log_calls(add)
add(2, 3)   # prints "calling add", returns 5
Decorators are used throughout web frameworks, testing libraries, and the standard library (@staticmethod, @classmethod, @property).

Concurrency

Fearless concurrency: the compiler enforces thread safety

Rust’s ownership and type system make data races a compile-time error, not a runtime surprise. The two key guarantees:

A value can be sent to another thread only if its type implements Send
A value can be shared (via reference) across threads only if its type implements Sync

The compiler enforces these automatically. If you try to share a non-thread-safe type across threads, it will not compile.

Threads
std::thread::spawn starts a new OS thread. It takes a closure that captures the values it needs. The move keyword transfers ownership of captured values into the thread — required because the spawned thread may outlive the calling scope.
use std::thread;

let handle = thread::spawn(move || {
    println!("running in a new thread");
});

handle.join().unwrap();   // wait for the thread to finish
spawn returns a JoinHandle&lt;T&gt; where T is whatever the closure returns. .join() blocks until the thread finishes and returns Result&lt;T, _&gt;.

Spawning multiple threads
use std::thread;

let handles: Vec&lt;_&gt; = (0..5).map(|i| {
    thread::spawn(move || {
        println!("thread {}", i);
    })
}).collect();

for handle in handles {
    handle.join().unwrap();
}



Shared State with Mutex&lt;T&gt;
A Mutex&lt;T&gt; (mutual exclusion lock) protects a value so only one thread can access it at a time. You access the value by calling .lock(), which blocks until the lock is available and returns a MutexGuard&lt;T&gt;. The guard releases the lock automatically when it goes out of scope.
use std::sync::Mutex;

let m = Mutex::new(0);

{
    let mut val = m.lock().unwrap();
    *val += 1;
}   // lock released here
.lock() returns Result because it can fail if the previous lock holder panicked while holding it (a “poisoned” mutex). .unwrap() is common in practice — a poisoned mutex usually means something has gone badly wrong already.


Arc&lt;Mutex&lt;T&gt;&gt;: Shared Mutable State Across Threads
To share mutable state across multiple threads you need both:

Arc&lt;T&gt; — shared ownership across threads (thread-safe reference counting)
Mutex&lt;T&gt; — exclusive access for mutation

Combined as Arc&lt;Mutex&lt;T&gt;&gt;, this is the standard pattern for shared mutable state in Rust. It is the direct equivalent of a shared_ptr&lt;mutex&gt; guarding a value in C++, but the compiler verifies you always lock before accessing.
use std::sync::{Arc, Mutex};
use std::thread;

let counter = Arc::new(Mutex::new(0));

let handles: Vec&lt;_&gt; = (0..10).map(|_| {
    let counter = Arc::clone(&counter);
    thread::spawn(move || {
        let mut val = counter.lock().unwrap();
        *val += 1;
    })
}).collect();

for handle in handles {
    handle.join().unwrap();
}

println!("final count: {}", *counter.lock().unwrap());  // 10
Each thread gets its own Arc clone (cheap: just increments a reference count). Each clone points to the same Mutex. Only one thread can hold the lock at a time, so the increments are safe.


Message Passing with Channels
An alternative to shared state: send values between threads via a channel. std::sync::mpsc provides a multi-producer, single-consumer channel.
use std::sync::mpsc;
use std::thread;

let (sender, receiver) = mpsc::channel();

thread::spawn(move || {
    sender.send(42).unwrap();
});

let value = receiver.recv().unwrap();
println!("received: {}", value);   // 42
send takes ownership of the value — it is moved into the channel. recv blocks until a value arrives and returns Result&lt;T, _&gt;. Use try_recv for a non-blocking check that returns immediately with Err if nothing is ready.
Multiple producers are supported by cloning the sender:
let sender2 = sender.clone();


